  private def extractSettings(root: Elem): Either[ParseError, Settings] = {
    val directSettings =
      (root \\ "setting").flatMap { node =>
        val key = node.attribute("key").map(_.text.trim).getOrElse("")
        val value = node.attribute("value").map(_.text.trim).filter(_.nonEmpty).getOrElse(node.text.trim)
        if (key.nonEmpty) Some(key -> value) else None
      }.toMap

    val nestedSettings =
      (root \\ "settings").flatMap { settingsNode =>
        settingsNode.child.collect {
          case node if node.label == "entry" =>
            val key = node.attribute("key").map(_.text.trim).getOrElse("")
            val value = node.attribute("value").map(_.text.trim).filter(_.nonEmpty).getOrElse(node.text.trim)
            key -> value
        }.filter(_._1.nonEmpty)
      }.toMap

    val all = directSettings ++ nestedSettings

    if (all.isEmpty) Left(InvalidConfiguration("No settings found in XML configuration"))
    else Right(Settings(all))
  }

  private def stripDoctypeAndEntities(xml: String): String = {
    xml
      .replaceAll("(?is)<!DOCTYPE[^>]*(\\[[\\s\\S]*?\\])?>", "")
      .replaceAll("(?is)<!ENTITY[^>]+>", "")
